{
  "sentences": [
    {
      "text": "這個衣服有瑕疵，我想退貨。",
      "pinyin": "Zhège yīfu yǒu xiácī, wǒ xiǎng tuìhuò.",
      "pinyin_numeric": "zhe4 ge5 yi1 fu5 you3 xia2 ci1, wo3 xiang3 tui4 huo4.",
      "translation_en": "This clothing has a defect; I want to return it.",
      "translation_ko": "이 옷에 하자가 있어서 환불하고 싶습니다."
    },
    {
      "text": "我的手機壞掉了，可以換貨嗎？",
      "pinyin": "Wǒ de shǒujī huài diào le, kěyǐ huànhuò ma?",
      "pinyin_numeric": "wo3 de5 shou3 ji1 huai4 diao4 le5, ke3 yi3 huan4 huo4 ma5?",
      "translation_en": "My phone is broken; can I exchange it?",
      "translation_ko": "제 휴대폰이 고장 났는데 교환할 수 있나요?"
    },
    {
      "text": "這個杯子破掉了，我要退錢。",
      "pinyin": "Zhège bēizi pò diào le, wǒ yào tuì qián.",
      "pinyin_numeric": "zhe4 ge5 bei1 zi5 po4 diao4 le5, wo3 yao4 tui4 qian2.",
      "translation_en": "This cup is broken; I want a refund.",
      "translation_ko": "이 컵이 깨졌는데 환불해 주세요."
    },
    {
      "text": "這本書髒掉了，可以換一本新的嗎？",
      "pinyin": "Zhè běn shū zāng diào le, kěyǐ huàn yī běn xīn de ma?",
      "pinyin_numeric": "zhe4 ben3 shu1 zang1 diao4 le5, ke3 yi3 huan4 yi1 ben3 xin1 de5 ma5?",
      "translation_en": "This book is dirty; can I exchange it for a new one?",
      "translation_ko": "이 책이 더러워졌는데 새 책으로 교환할 수 있나요?"
    },
    {
      "text": "我買的鞋子尺寸不合，想要退貨。",
      "pinyin": "Wǒ mǎi de xiézi chǐcùn bù hé, xiǎng yào tuìhuò.",
      "pinyin_numeric": "wo3 mai3 de5 xie2 zi5 chi3 cun4 bu4 he2, xiang3 yao4 tui4 huo4.",
      "translation_en": "The shoes I bought don't fit; I want to return them.",
      "translation_ko": "제가 산 신발 사이즈가 맞지 않아서 환불하고 싶습니다."
    },
    {
      "text": "這個顏色不對，我要換貨。",
      "pinyin": "Zhège yánsè bù duì, wǒ yào huànhuò.",
      "pinyin_numeric": "zhe4 ge5 yan2 se4 bu4 dui4, wo3 yao4 huan4 huo4.",
      "translation_en": "This color is wrong; I want to exchange it.",
      "translation_ko": "색상이 맞지 않아서 교환하고 싶습니다."
    },
    {
      "text": "你送錯東西了，我要退貨。",
      "pinyin": "Nǐ sòng cuò dōngxi le, wǒ yào tuìhuò.",
      "pinyin_numeric": "ni3 song4 cuo4 dong1 xi5 le5, wo3 yao4 tui4 huo4.",
      "translation_en": "You sent the wrong item; I want to return it.",
      "translation_ko": "물건을 잘못 보내셨는데 환불하고 싶습니다."
    },
    {
      "text": "這個包包有問題，拉鍊壞掉了。",
      "pinyin": "Zhège bāobāo yǒu wèntí, lāliàn huài diào le.",
      "pinyin_numeric": "zhe4 ge5 bao1 bao1 you3 wen4 ti2, la1 lian4 huai4 diao4 le5.",
      "translation_en": "This bag has a problem; the zipper is broken.",
      "translation_ko": "이 가방에 문제가 있는데 지퍼가 고장 났습니다."
    },
    {
      "text": "我買的雞蛋有幾個破掉了，可以退錢嗎？",
      "pinyin": "Wǒ mǎi de jīdàn yǒu jǐ ge pò diào le, kěyǐ tuì qián ma?",
      "pinyin_numeric": "wo3 mai3 de5 ji1 dan4 you3 ji3 ge5 po4 diao4 le5, ke3 yi3 tui4 qian2 ma5?",
      "translation_en": "Some of the eggs I bought are broken; can I get a refund?",
      "translation_ko": "제가 산 계란 중에 몇 개가 깨졌는데 환불받을 수 있나요?"
    },
    {
      "text": "這個手機殼有瑕疵，我要換貨。",
      "pinyin": "Zhège shǒujī ké yǒu xiácī, wǒ yào huànhuò.",
      "pinyin_numeric": "zhe4 ge5 shou3 ji1 ke2 you3 xia2 ci1, wo3 yao4 huan4 huo4.",
      "translation_en": "This phone case has a defect; I want to exchange it.",
      "translation_ko": "이 휴대폰 케이스에 하자가 있어서 교환하고 싶습니다."
    }
  ]
}
